const item = $input.first();
const now = new Date();
const iso = now.toISOString();
const stamp = iso.slice(0, 19).split('-').join('').split(':').join('').split('T').join('-');
const random = Math.random().toString(16).slice(2, 8).padEnd(6, '0');
const jobId = stamp + '-' + random;
function trimTrailingSlash(value) {
  let text = String(value || '');
  while (text.endsWith('/')) text = text.slice(0, -1);
  return text;
}
const repoDir = trimTrailingSlash($env.VIDEO_CLIP_REPO_DIR || '/Users/stephenqiu/Desktop/Repository/n8n');
const baseDir = trimTrailingSlash($env.VIDEO_CLIP_JOBS_DIR || repoDir + '/tmp/n8n-video-jobs');
const jobDir = baseDir + '/' + jobId;
return [{ json: { ...item.json, jobId, baseDir, repoDir, jobDir, inputsDir: jobDir + '/inputs', ttsDir: jobDir + '/tts', ttsSegmentsDir: jobDir + '/tts/segments', renderDir: jobDir + '/render' }, binary: item.binary }];

const fs = require('fs');
const item = $input.first();
const binary = item.binary || {};
const keyAliases = {
  coverImage: ['cover_image', 'coverImage'],
  screenshotImage: ['proof_screenshot', 'proofScreenshot'],
  backgroundVideo: ['background_video', 'backgroundVideo']
};
function firstBinaryKey(keys) { return keys.find((key) => binary[key]); }
function cleanText(value) {
  const lf = String.fromCharCode(10);
  const cr = String.fromCharCode(13);
  let text = String(value || '').split(String.fromCharCode(0)).join('').split(cr + lf).join(lf).split(cr).join(lf);
  while (text.includes(lf + lf + lf)) text = text.split(lf + lf + lf).join(lf + lf);
  return text.trim();
}
const uploadKeys = {
  coverImage: firstBinaryKey(keyAliases.coverImage),
  screenshotImage: firstBinaryKey(keyAliases.screenshotImage),
  backgroundVideo: firstBinaryKey(keyAliases.backgroundVideo)
};
for (const [name, key] of Object.entries(uploadKeys)) {
  if (!key) throw new Error('Missing uploaded file: ' + name + '. Accepted field names: ' + keyAliases[name].join(', '));
}
const viewpoint = cleanText(item.json.viewpoint);
if (!viewpoint) throw new Error('viewpoint is required');
const scriptMode = 'ai_podcast';
const scriptStyle = item.json.podcast_style || 'podcast_interview';
const selectedVoices = {
  voiceSingle: item.json.voice_single || '男主持 - 温柔阿虎｜host_male_wennuanahu',
  voiceA: item.json.voice_a || '男主持 - 温柔阿虎｜host_male_wennuanahu',
  voiceB: item.json.voice_b || '女嘉宾 - 小何｜guest_female_xiaohe'
};
fs.mkdirSync(item.json.inputsDir, { recursive: true });
fs.mkdirSync(item.json.ttsDir, { recursive: true });
fs.mkdirSync(item.json.ttsSegmentsDir, { recursive: true });
fs.mkdirSync(item.json.renderDir, { recursive: true });
const files = {
  coverImage: item.json.inputsDir + '/cover.png',
  screenshotImage: item.json.inputsDir + '/screenshot.png',
  backgroundVideo: item.json.inputsDir + '/background.mp4',
  scriptText: item.json.inputsDir + '/script.txt',
  generatedScript: item.json.inputsDir + '/generated-script.json',
  llmPrompt: item.json.inputsDir + '/script-prompt.txt',
  llmResponse: item.json.inputsDir + '/script-response.json'
};
for (const [inputName, target] of [['coverImage', files.coverImage], ['screenshotImage', files.screenshotImage], ['backgroundVideo', files.backgroundVideo]]) {
  const buffer = await this.helpers.getBinaryDataBuffer(0, uploadKeys[inputName]);
  fs.writeFileSync(target, buffer);
}
return [{ json: { ...item.json, files, viewpoint, scriptMode, scriptStyle, selectedVoices } }];

const fs = require('fs');
const item = $input.first().json;
const job = {
  jobId: item.jobId,
  inputs: {
    coverImage: item.files.coverImage,
    screenshotImage: item.files.screenshotImage,
    backgroundVideo: item.files.backgroundVideo,
    scriptText: item.files.scriptText,
