const video = fs.readFileSync(item.outputVideo);
const size = video.length;
if (size === 0) throw new Error('Final video is empty: ' + item.outputVideo);
const binary = { finalVideo: await this.helpers.prepareBinaryData(video, 'final.mp4', 'video/mp4') };
if (item.audioPath && fs.existsSync(item.audioPath)) {
  const audio = fs.readFileSync(item.audioPath);
  binary.ttsAudio = await this.helpers.prepareBinaryData(audio, 'tts-audio.mp3', 'audio/mpeg');
}
return [{ json: { jobId: item.jobId, jobDir: item.jobDir, reviewDir: item.jobDir, videoPath: item.outputVideo, audioPath: item.audioPath, subtitlePath: item.subtitlePath, subtitleTimingPath: item.ttsTimingPath, transcriptPath: item.transcriptPath, costPath: item.costPath, podcastMetadataPath: item.podcastMetadataPath, podcastRawResponsePath: item.podcastRawResponsePath, ffmpegLog: item.ffmpegLog, size, generatedScriptText: item.generatedScriptText, generatedScriptTitle: item.generatedScriptTitle, generatedScriptSummary: item.generatedScriptSummary, scriptMode: item.scriptMode, selectedVoices: item.selectedVoices, ttsDuration: item.ttsDuration, ttsPauseSeconds: item.ttsPauseSeconds, cost: item.cost }, binary }];

const fs = require('fs');
const item = $input.first().json;
function normalizeChoice(value, fallback) {
  const text = String(value || '').trim();
  if (!text) return fallback;
  const separatorIndex = text.lastIndexOf('｜');
  return separatorIndex >= 0 ? text.slice(separatorIndex + 1).trim() : text;
}
const podcastSpeakerA = normalizeChoice(item.podcast_speaker_a, $env.DOUBAO_AI_PODCAST_SPEAKER_A || 'zh_male_dayi_v2_saturn_bigtts');
const podcastSpeakerB = normalizeChoice(item.podcast_speaker_b, $env.DOUBAO_AI_PODCAST_SPEAKER_B || 'zh_female_mizai_v2_saturn_bigtts');
