  '开场要有播客感，可以使用“今天我们要聊的话题是...”这类自然引子，但不要机械朗读。',
  '整体要适合短视频，表达紧凑，主持人负责提出主题和追问，嘉宾负责解释、举例和回应。',
  '不要输出字幕文件，不要输出 Markdown，只生成适合服务合成的播客内容。',
  '',
  '播客风格：' + style,
  '用户观点：' + item.viewpoint,
].join(String.fromCharCode(10));
fs.writeFileSync(item.files.scriptText, podcastInputText, 'utf8');
const aiPodcastJobPath = item.jobDir + '/ai-podcast-job.json';
const aiPodcastJob = {
  jobId: item.jobId,
  podcastInputText,
  podcastSpeakerA,
  podcastSpeakerB,
  useHeadMusic,
  ttsDir: item.ttsDir,
  audioPath: item.ttsDir + '/audio.mp3',
  ttsTimingPath: item.ttsDir + '/timing.json',
  podcastMetadataPath: item.ttsDir + '/ai-podcast-metadata.json',
  podcastRawResponsePath: item.ttsDir + '/ai-podcast-response.binlog',
  costPath: item.ttsDir + '/cost.json',
  transcriptPath: item.ttsDir + '/transcript.txt'
};
fs.writeFileSync(aiPodcastJobPath, JSON.stringify(aiPodcastJob, null, 2), 'utf8');
return [{ json: { ...item, podcastInputText, podcastSpeakerA, podcastSpeakerB, useHeadMusic, aiPodcastJobPath, audioPath: aiPodcastJob.audioPath, ttsTimingPath: aiPodcastJob.ttsTimingPath, costPath: aiPodcastJob.costPath, transcriptPath: aiPodcastJob.transcriptPath, podcastMetadataPath: aiPodcastJob.podcastMetadataPath, podcastRawResponsePath: aiPodcastJob.podcastRawResponsePath, generatedScriptText: podcastInputText, generatedScriptTitle: 'AI Podcast', generatedScriptSummary: item.viewpoint, scriptMode: 'ai_podcast', selectedVoices: { podcastSpeakerA, podcastSpeakerB } } }];

const fs = require('fs');
const { spawnSync } = require('child_process');
const item = $input.first().json;
const scriptPath = item.repoDir + '/tools/video-composer/ai-podcast-client.mjs';
const result = spawnSync('node', [scriptPath, item.aiPodcastJobPath], {
  cwd: item.repoDir,
  encoding: 'utf8',
  maxBuffer: 1024 * 1024 * 20,
});
if (result.error) throw result.error;
if (result.status !== 0) {
  throw new Error('AI podcast client failed with exit code ' + result.status + ': ' + (result.stderr || result.stdout));
}
const audio = fs.readFileSync(item.audioPath);
const podcastAudio = await this.helpers.prepareBinaryData(audio, 'ai-podcast-audio.mp3', 'audio/mpeg');
const cost = item.costPath && fs.existsSync(item.costPath) ? JSON.parse(fs.readFileSync(item.costPath, 'utf8')) : null;
const transcriptText = item.transcriptPath && fs.existsSync(item.transcriptPath) ? fs.readFileSync(item.transcriptPath, 'utf8').trim() : '';
let aiPodcastResult = null;
try {
  const lines = String(result.stdout || '').trim().split(/\n/).filter(Boolean);
  aiPodcastResult = lines.length ? JSON.parse(lines[lines.length - 1]) : null;
} catch {}
return [{ json: { ...item, aiPodcastStdout: result.stdout, aiPodcastResult, cost, transcriptText, generatedScriptText: transcriptText || item.generatedScriptText }, binary: { podcastAudio } }];
